## Approach: DFS + BFS

Use DFS to find and mark all cells of the first island. Then BFS outward from that island, counting levels until reaching the second island.

```javascript
function shortestBridge(grid) {
  const n = grid.length, dirs = [[0,1],[0,-1],[1,0],[-1,0]];
  const queue = [];
  let found = false;
  function dfs(r, c) {
    if (r < 0 || r >= n || c < 0 || c >= n || grid[r][c] !== 1) return;
    grid[r][c] = 2;
    queue.push([r, c]);
    for (const [dr, dc] of dirs) dfs(r + dr, c + dc);
  }
  for (let i = 0; i < n && !found; i++)
    for (let j = 0; j < n && !found; j++)
      if (grid[i][j] === 1) { dfs(i, j); found = true; }
  let steps = 0;
  while (queue.length) {
    const size = queue.length;
    for (let q = 0; q < size; q++) {
      const [r, c] = queue.shift();
      for (const [dr, dc] of dirs) {
        const nr = r + dr, nc = c + dc;
        if (nr >= 0 && nr < n && nc >= 0 && nc < n) {
          if (grid[nr][nc] === 1) return steps;
          if (grid[nr][nc] === 0) { grid[nr][nc] = 2; queue.push([nr, nc]); }
        }
      }
    }
    steps++;
  }
  return -1;
}
```

**Time Complexity:** O(n²)
**Space Complexity:** O(n²)

