## Approach: BFS

Perform BFS from the source position. At each step, explore all 8 possible knight moves. Track visited cells to avoid revisiting.

```javascript
function stepsByKnight(n, source, target) {
  if (source[0] === target[0] && source[1] === target[1]) return 0;
  const moves = [[-2,-1],[-2,1],[-1,-2],[-1,2],[1,-2],[1,2],[2,-1],[2,1]];
  const visited = new Set([source.toString()]);
  const queue = [[source[0], source[1], 0]];
  while (queue.length) {
    const [r, c, steps] = queue.shift();
    for (const [dr, dc] of moves) {
      const nr = r + dr, nc = c + dc;
      if (nr === target[0] && nc === target[1]) return steps + 1;
      const key = nr + ',' + nc;
      if (nr >= 1 && nr <= n && nc >= 1 && nc <= n && !visited.has(key)) {
        visited.add(key);
        queue.push([nr, nc, steps + 1]);
      }
    }
  }
  return -1;
}
```

