## Approach: Kosaraju's Algorithm

Do DFS to get finish-order stack, transpose the graph, then DFS on transposed graph in reverse finish order. If the second DFS visits all nodes from the first start, the graph is strongly connected.

```javascript
function stronglyConnected(v, edges) {
  const adj = Array.from({length: v}, () => []);
  const radj = Array.from({length: v}, () => []);
  for (const [u, w] of edges) { adj[u].push(w); radj[w].push(u); }
  const visited = new Array(v).fill(false);
  const stack = [];
  function dfs1(u) {
    visited[u] = true;
    for (const w of adj[u]) if (!visited[w]) dfs1(w);
    stack.push(u);
  }
  for (let i = 0; i < v; i++) if (!visited[i]) dfs1(i);
  visited.fill(false);
  function dfs2(u) {
    visited[u] = true;
    for (const w of radj[u]) if (!visited[w]) dfs2(w);
  }
  dfs2(stack[stack.length - 1]);
  return visited.every(Boolean) ? 1 : 0;
}
```

**Time Complexity:** O(V + E)
**Space Complexity:** O(V + E)

