## Approach: Monotonic Stack

For each element, find how many subarrays it's the minimum of using previous-less-element and next-less-element distances via a monotonic stack.

```javascript
function sumOfSubarrayMinimums(arr) {
  const MOD = 1e9 + 7, n = arr.length;
  const left = new Array(n), right = new Array(n);
  const stack = [];
  for (let i = 0; i < n; i++) {
    while (stack.length && arr[stack[stack.length - 1]] >= arr[i]) stack.pop();
    left[i] = stack.length ? i - stack[stack.length - 1] : i + 1;
    stack.push(i);
  }
  stack.length = 0;
  for (let i = n - 1; i >= 0; i--) {
    while (stack.length && arr[stack[stack.length - 1]] > arr[i]) stack.pop();
    right[i] = stack.length ? stack[stack.length - 1] - i : n - i;
    stack.push(i);
  }
  let result = 0;
  for (let i = 0; i < n; i++)
    result = (result + arr[i] * left[i] * right[i]) % MOD;
  return result;
}
```

