## Approach: Binary Search + BFS

Binary search on time `t`. For each `t`, BFS/DFS to check if a path exists from `(0,0)` to `(n-1,n-1)` using only cells with elevation `<= t`.

```javascript
function swimInRisingWater(grid) {
  const n = grid.length;
  const canReach = (t) => {
    if (grid[0][0] > t) return false;
    const visited = Array.from({length: n}, () => new Array(n).fill(false));
    const queue = [[0, 0]];
    visited[0][0] = true;
    const dirs = [[0,1],[0,-1],[1,0],[-1,0]];
    while (queue.length) {
      const [r, c] = queue.shift();
      if (r === n-1 && c === n-1) return true;
      for (const [dr, dc] of dirs) {
        const nr = r+dr, nc = c+dc;
        if (nr>=0 && nr<n && nc>=0 && nc<n && !visited[nr][nc] && grid[nr][nc]<=t) {
          visited[nr][nc] = true;
          queue.push([nr, nc]);
        }
      }
    }
    return false;
  };
  let lo = grid[0][0], hi = n * n - 1;
  while (lo < hi) {
    const mid = (lo + hi) >> 1;
    if (canReach(mid)) hi = mid;
    else lo = mid + 1;
  }
  return lo;
}
```

