## Approach: Node-Based Trie

Each node has a map of children and an `isEnd` flag. Insert by traversing/creating nodes. Search checks `isEnd` at the last character. StartsWith only needs to reach the last character.

```javascript
function trieDataStructure(operations, args) {
  const root = {};
  const insert = (word) => {
    let node = root;
    for (const ch of word) { if (!node[ch]) node[ch] = {}; node = node[ch]; }
    node.end = true;
  };
  const search = (word) => {
    let node = root;
    for (const ch of word) { if (!node[ch]) return false; node = node[ch]; }
    return !!node.end;
  };
  const startsWith = (prefix) => {
    let node = root;
    for (const ch of prefix) { if (!node[ch]) return false; node = node[ch]; }
    return true;
  };
  const fns = { insert, search, startsWith };
  return operations.map((op, i) => {
    if (op === 'Trie') return null;
    return fns[op](...args[i]) ?? null;
  });
}
```

